class SecureAuthService(AuthServiceServicer):
    def __init__(self):
        self.users = {
            'admin': self._hash_password('admin123'),
            'user1': self._hash_password('password123')
        }
        self.active_tokens: Dict[str, dict] = {}
        self.failed_attempts: Dict[str, list] = {}
        self.max_attempts = 5
        self.lockout_duration = 300
    
    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()
    
    def _validate_username(self, username: str) -> bool:
        if not username or len(username) < 3 or len(username) > 50:
            return False
        return bool(re.match(r'^[a-zA-Z0-9_]+$', username))
    
    def _validate_password(self, password: str) -> bool:
        if not password or len(password) < 6 or len(password) > 128:
            return False
        return True
    
    def _is_locked_out(self, username: str) -> bool:
        if username not in self.failed_attempts:
            return False
        
        attempts = self.failed_attempts[username]
        recent_attempts = [t for t in attempts if time.time() - t < self.lockout_duration]
        self.failed_attempts[username] = recent_attempts
        
        return len(recent_attempts) >= self.max_attempts
    
    def _record_failed_attempt(self, username: str):
        if username not in self.failed_attempts:
            self.failed_attempts[username] = []
        self.failed_attempts[username].append(time.time())
    
    def _generate_token(self) -> str:
        return secrets.token_urlsafe(32)
    
    def _validate_token(self, token: str) -> bool:
        if not token or token not in self.active_tokens:
            return False
        
        token_data = self.active_tokens[token]
        if time.time() - token_data['created'] > 3600:
            del self.active_tokens[token]
            return False
        
        return True
    
    def Login(self, request, context):
        username = request.username
        password = request.password
        
        if not self._validate_username(username):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details('Invalid username format')
            return LoginResponse(success=False, message='Invalid username format')
        
        if not self._validate_password(password):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details('Invalid password format')
            return LoginResponse(success=False, message='Invalid password format')
        
        if self._is_locked_out(username):
            context.set_code(grpc.StatusCode.RESOURCE_EXHAUSTED)
            context.set_details('Account temporarily locked due to too many failed attempts')
            return LoginResponse(success=False, message='Account locked')
        
        if username not in self.users:
            self._record_failed_attempt(username)
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid credentials')
            return LoginResponse(success=False, message='Invalid credentials')
        
        password_hash = self._hash_password(password)
        if self.users[username] != password_hash:
            self._record_failed_attempt(username)
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid credentials')
            return LoginResponse(success=False, message='Invalid credentials')
        
        if username in self.failed_attempts:
            del self.failed_attempts[username]
        
        token = self._generate_token()
        self.active_tokens[token] = {
            'username': username,
            'created': time.time()
        }
        
        return LoginResponse(success=True, token=token, message='Login successful')
    
    def Logout(self, request, context):
        token = request.token
        
        if not token:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details('Token required')
            return LogoutResponse(success=False, message='Token required')
        
        if token in self.active_tokens:
            del self.active_tokens[token]
            return LogoutResponse(success=True, message='Logout successful')
        
        context.set_code(grpc.StatusCode.NOT_FOUND)
        context.set_details('Invalid token')
        return LogoutResponse(success=False, message='Invalid token')
    
    def get_username_from_token(self, token: str) -> str:
        if self._validate_token(token):
            return self.active_tokens[token]['username']
        return None

